class Solution {
public:
int findDuplicateSubstring(string s, int n) {
	int result = -1;
	for (int i = 0; i < s.size() - n + 1; i++) {
		string substr = s.substr(i, n);
		if (result != -1) break;
		for (int j = i + 1; j < s.size() - n + 1; j++) {
			if (s.substr(j, n) == substr) {
				result = i;
				break;
			}
		}
	}
	return result;
}
};

